use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_engine(size: usize) -> ExecutionEngine {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE orders (id INTEGER, amount INTEGER)").unwrap())
        .unwrap();

    for i in 0..size {
        engine
            .execute(parse(&format!("INSERT INTO orders VALUES ({}, {})", i, i * 10)).unwrap())
            .unwrap();
    }
    engine
}

fn bench_aggregate_count(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_count");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("count_star", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT COUNT(*) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_sum(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_sum");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("sum_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT SUM(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_avg(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_avg");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("avg_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT AVG(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_min_max(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_min_max");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("min_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT MIN(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });

        group.bench_with_input(BenchmarkId::new("max_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT MAX(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_multiple(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_multiple");

    for size in [100, 1000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("count_sum_avg", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(
                        parse("SELECT COUNT(*), SUM(amount), AVG(amount) FROM orders").unwrap(),
                    )
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_aggregate_count,
    bench_aggregate_sum,
    bench_aggregate_avg,
    bench_aggregate_min_max,
    bench_aggregate_multiple
);
criterion_main!(benches);

//! Insert Benchmark - benches/bench_insert.rs
//!
//! INSERT performance benchmark for SQLRustGo using StorageEngine

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo_storage::{ColumnDefinition, MemoryStorage, StorageEngine, TableInfo};
use sqlrustgo_types::Value;

/// Generate test data rows
fn generate_rows(count: usize) -> Vec<Vec<Value>> {
    (0..count).map(|i| vec![Value::Integer(i as i64)]).collect()
}

/// Create test table info
fn create_table_info() -> TableInfo {
    TableInfo {
        name: "bench".to_string(),
        columns: vec![ColumnDefinition {
            name: "id".to_string(),
            data_type: "INTEGER".to_string(),
            nullable: false,
        }],
    }
}

/// Benchmark INSERT with different data sizes using MemoryStorage
fn bench_insert_sizes(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert");

    for size in [1_000, 10_000, 100_000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut storage = MemoryStorage::new();
                storage.create_table(&create_table_info()).unwrap();
                let rows = generate_rows(size);
                storage.insert("bench", rows).unwrap();
            });
        });
    }

    group.finish();
}

/// Benchmark batch INSERT performance
fn bench_insert_batch(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_batch");

    for batch_size in [10, 100, 1000] {
        let total_rows = 10_000;
        group.bench_with_input(
            BenchmarkId::from_parameter(batch_size),
            &batch_size,
            |b, &batch_size| {
                b.iter(|| {
                    let mut storage = MemoryStorage::new();
                    storage.create_table(&create_table_info()).unwrap();

                    let mut batch = Vec::with_capacity(batch_size);
                    for i in 0..total_rows {
                        batch.push(vec![Value::Integer(i as i64)]);
                        if batch.len() >= batch_size {
                            storage.insert("bench", std::mem::take(&mut batch)).unwrap();
                            batch = Vec::with_capacity(batch_size);
                        }
                    }
                    if !batch.is_empty() {
                        storage.insert("bench", batch).unwrap();
                    }
                });
            },
        );
    }

    group.finish();
}

/// Benchmark INSERT with multiple columns
fn bench_insert_multi_column(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_multi_column");

    let table_info = TableInfo {
        name: "bench".to_string(),
        columns: vec![
            ColumnDefinition {
                name: "id".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: false,
            },
            ColumnDefinition {
                name: "name".to_string(),
                data_type: "TEXT".to_string(),
                nullable: true,
            },
            ColumnDefinition {
                name: "value".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: true,
            },
        ],
    };

    for size in [1_000, 10_000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut storage = MemoryStorage::new();
                storage.create_table(&table_info).unwrap();

                let rows: Vec<Vec<Value>> = (0..size)
                    .map(|i| {
                        vec![
                            Value::Integer(i as i64),
                            Value::Text(format!("user_{}", i)),
                            Value::Integer((i * 10) as i64),
                        ]
                    })
                    .collect();
                storage.insert("bench", rows).unwrap();
            });
        });
    }

    group.finish();
}

/// Measure throughput (rows/s) for 100k insert
fn bench_insert_throughput(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_throughput");

    group.bench_function("100k_rows", |b| {
        b.iter(|| {
            let mut storage = MemoryStorage::new();
            storage.create_table(&create_table_info()).unwrap();
            let rows = generate_rows(100_000);
            storage.insert("bench", rows).unwrap();
        });
    });

    group.finish();
}

criterion_group!(
    benches,
    bench_insert_sizes,
    bench_insert_batch,
    bench_insert_multi_column,
    bench_insert_throughput
);
criterion_main!(benches);

//! Scan Benchmark for SQLRustGo
//!
//! Benchmarks for full table scan operations.

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_engine_with_data(rows: usize) -> ExecutionEngine {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE scan_bench (id INTEGER, name TEXT, value INTEGER)").unwrap())
        .unwrap();

    for i in 0..rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO scan_bench VALUES ({}, 'name_{}', {})",
                    i,
                    i % 1000,
                    i
                ))
                .unwrap(),
            )
            .unwrap();
    }

    engine
}

fn bench_scan_1k(c: &mut Criterion) {
    let mut engine = setup_engine_with_data(1_000);

    c.bench_function("scan_1k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM scan_bench").unwrap())
                .unwrap()
        });
    });
}

fn bench_scan_10k(c: &mut Criterion) {
    let mut engine = setup_engine_with_data(10_000);

    c.bench_function("scan_10k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM scan_bench").unwrap())
                .unwrap()
        });
    });
}

fn bench_scan_100k(c: &mut Criterion) {
    let mut engine = setup_engine_with_data(100_000);

    c.bench_function("scan_100k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM scan_bench").unwrap())
                .unwrap()
        });
    });
}

fn bench_scan_with_filter(c: &mut Criterion) {
    let mut group = c.benchmark_group("scan_with_filter");

    for size in [1_000, 10_000, 100_000] {
        let mut engine = setup_engine_with_data(size);

        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM scan_bench WHERE value > 500").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_scan_projection(c: &mut Criterion) {
    let mut group = c.benchmark_group("scan_projection");

    for size in [1_000, 10_000, 100_000] {
        let mut engine = setup_engine_with_data(size);

        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT id, value FROM scan_bench").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_scan_1k,
    bench_scan_10k,
    bench_scan_100k,
    bench_scan_with_filter,
    bench_scan_projection
);
criterion_main!(benches);

//! Dataset Generator - benches/dataset_generator.rs
//!
//! Reusable test data generation utilities for SQLRustGo benchmarks.

use sqlrustgo_storage::{ColumnDefinition, TableInfo};
use sqlrustgo_types::Value;

/// Generate sequential integer rows
pub fn generate_integer_rows(count: usize) -> Vec<Vec<Value>> {
    (0..count).map(|i| vec![Value::Integer(i as i64)]).collect()
}

/// Generate rows with multiple columns (id, name, value)
pub fn generate_multi_column_rows(count: usize) -> Vec<Vec<Value>> {
    (0..count)
        .map(|i| {
            vec![
                Value::Integer(i as i64),
                Value::Text(format!("user_{}", i)),
                Value::Integer((i * 10) as i64),
            ]
        })
        .collect()
}

/// Generate rows with random-ish distribution for testing
pub fn generate_ordered_rows(count: usize) -> Vec<Vec<Value>> {
    (0..count)
        .map(|i| {
            let value = if i % 2 == 0 { i } else { count - i };
            vec![Value::Integer(i as i64), Value::Integer(value as i64)]
        })
        .collect()
}

/// Create a simple table info with single INTEGER column
pub fn simple_table_info(name: &str) -> TableInfo {
    TableInfo {
        name: name.to_string(),
        columns: vec![ColumnDefinition {
            name: "id".to_string(),
            data_type: "INTEGER".to_string(),
            nullable: false,
        }],
    }
}

/// Create a multi-column table info
pub fn multi_column_table_info(name: &str) -> TableInfo {
    TableInfo {
        name: name.to_string(),
        columns: vec![
            ColumnDefinition {
                name: "id".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: false,
            },
            ColumnDefinition {
                name: "name".to_string(),
                data_type: "TEXT".to_string(),
                nullable: true,
            },
            ColumnDefinition {
                name: "value".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: true,
            },
        ],
    }
}

/// Create an orders table for aggregate testing
pub fn orders_table_info() -> TableInfo {
    TableInfo {
        name: "orders".to_string(),
        columns: vec![
            ColumnDefinition {
                name: "id".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: false,
            },
            ColumnDefinition {
                name: "amount".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: false,
            },
        ],
    }
}

/// Generate orders data for aggregate benchmarks
pub fn generate_orders(count: usize) -> Vec<Vec<Value>> {
    (0..count)
        .map(|i| vec![Value::Integer(i as i64), Value::Integer((i * 10) as i64)])
        .collect()
}

/// Benchmark dataset sizes
pub const BENCH_SIZES: [usize; 3] = [1_000, 10_000, 100_000];

/// Small dataset for quick tests
pub const SMALL_SIZES: [usize; 3] = [100, 1000, 10_000];

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_generate_integer_rows() {
        let rows = generate_integer_rows(100);
        assert_eq!(rows.len(), 100);
        assert_eq!(rows[0][0], Value::Integer(0));
        assert_eq!(rows[99][0], Value::Integer(99));
    }

    #[test]
    fn test_generate_multi_column_rows() {
        let rows = generate_multi_column_rows(10);
        assert_eq!(rows.len(), 10);
        assert_eq!(rows[0].len(), 3);
    }

    #[test]
    fn test_simple_table_info() {
        let info = simple_table_info("test");
        assert_eq!(info.name, "test");
        assert_eq!(info.columns.len(), 1);
    }

    #[test]
    fn test_orders_table_info() {
        let info = orders_table_info();
        assert_eq!(info.name, "orders");
        assert_eq!(info.columns.len(), 2);
    }

    #[test]
    fn test_generate_orders() {
        let rows = generate_orders(50);
        assert_eq!(rows.len(), 50);
        assert_eq!(rows[0][1], Value::Integer(0));
        assert_eq!(rows[10][1], Value::Integer(100));
    }
}

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn bench_executor_select_where(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE users (id INTEGER, name TEXT, age INTEGER)").unwrap())
        .unwrap();

    // Use 1000 rows for benchmark
    for i in 0..1000 {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO users VALUES ({}, 'user{}', {})",
                    i,
                    i,
                    i % 50
                ))
                .unwrap(),
            )
            .unwrap();
    }

    let mut group = c.benchmark_group("executor_select");

    group.bench_function("select_all_1k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM users").unwrap())
                .unwrap()
        });
    });

    group.bench_function("select_where_id_1k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM users WHERE id = 500").unwrap())
                .unwrap()
        });
    });

    group.bench_function("select_where_age_1k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM users WHERE age > 25").unwrap())
                .unwrap()
        });
    });

    group.finish();
}

fn bench_executor_insert(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE bench_insert (id INTEGER, value TEXT)").unwrap())
        .unwrap();

    let mut group = c.benchmark_group("executor_insert");

    for size in [1000, 10000, 100000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                for i in 0..size {
                    engine
                        .execute(
                            parse(&format!(
                                "INSERT INTO bench_insert VALUES ({}, 'value{}')",
                                i, i
                            ))
                            .unwrap(),
                        )
                        .unwrap();
                }
            });
        });
    }

    group.finish();
}

fn bench_executor_update(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE bench_update (id INTEGER, value INTEGER)").unwrap())
